+#[test]
+fn lua_negative_number_to_dynamic() {
+    let result = lua_value_to_dynamic(LuaValue::Number(-3.14)).unwrap();
+    if let DynValue::F64(f) = result {
+        assert!((f.into_inner() + 3.14).abs() < 1e-10);
+    } else {
